h1 { color: #00ff88; }
button { cursor: pointer; }
a { text-decoration: none; }

div {
  width: 200px;
  padding: 20px;
  border: 2px solid red;
  margin: 10px;
  box-sizing: border-box;
}

p { color: gray; }
.highlight { color: gold; }
#hero { font-size: 64px; }
