.card p { color: gray; }
.card > h2 { color: blue; }
h2 + p { margin-top: 0; }
[type="email"] { border: 2px solid blue; }

h1 {
  font-size: 48px;
  font-weight: 700;
  letter-spacing: -2px;
  line-height: 1.2;
  text-transform: uppercase;
}

.parent {
  position: relative;
}
.badge {
  position: absolute;
  top: -10px;
  right: -10px;
}

